**Key Security Controls**:
- Parameterized queries with `@Query` and bound parameters ensure the SQL structure is fixed and user input is treated as data, not code.
- Input validation and normalization (`InputValidator`) enforce length and character constraints, reducing the risk of malicious payloads.
- Robust error handling and logging ensure failures are handled safely, with suspicious input logged for investigation but without exposing internal SQL or stack traces to the user.

For dynamic filters and sorting in Room, you must constrain what can vary. User input should only influence data values (via bound parameters) or pick from a small, server-defined set of allowed columns/directions. Avoid letting raw user strings become SQL fragments.

**PRODUCTION PATTERN**:

```kotlin
import androidx.room.Dao
import androidx.room.Entity
import androidx.room.PrimaryKey
import androidx.room.RawQuery
import androidx.sqlite.db.SimpleSQLiteQuery
import androidx.sqlite.db.SupportSQLiteQuery
import android.util.Log

@Entity(tableName = "users")
data class User(
    @PrimaryKey(autoGenerate = true) val id: Long = 0,
    val username: String,
    val email: String,
    val isActive: Boolean
)

enum class SortField(val column: String) {
    USERNAME("username"),
    EMAIL("email"),
    ID("id")
}

enum class SortDirection(val sql: String) {
    ASC("ASC"),
    DESC("DESC")
}

@Dao
interface DynamicUserDao {
    @RawQuery
    fun searchDynamic(query: SupportSQLiteQuery): List<User>
}

class DynamicQueryBuilder {
    fun buildUserSearchQuery(
        term: String?,
        includeInactive: Boolean,
        sortField: SortField,
        sortDirection: SortDirection,
        limit: Int = 50,
        offset: Int = 0
    ): SupportSQLiteQuery {
        val sql = StringBuilder("SELECT * FROM users WHERE 1=1")
        val args = mutableListOf<Any>()

        // Value-based filters use placeholders
        if (!term.isNullOrBlank()) {
            sql.append(" AND (username LIKE ? OR email LIKE ?)")
            val pattern = "%${term.trim()}%"
            args.add(pattern)
            args.add(pattern)
        }

        if (!includeInactive) {
            sql.append(" AND isActive = ?")
            args.add(1)
        }

        // Column names and directions come only from enums (not user text)
        sql.append(" ORDER BY ")
            .append(sortField.column)
            .append(" ")
            .append(sortDirection.sql)

        // Pagination with sane limits
        val safeLimit = limit.coerceIn(1, 200)
        val safeOffset = offset.coerceAtLeast(0)
        sql.append(" LIMIT ? OFFSET ?")
        args.add(safeLimit)
        args.add(safeOffset)

        return SimpleSQLiteQuery(sql.toString(), args.toTypedArray())
    }
}

class AuditLogger {
    fun logSearchAttempt(ip: String?, term: String?, success: Boolean) {
        Log.i(
            "AuditLogger",
            "user_search ip=$ip termLength=${term?.length ?: 0} success=$success"
        )
    }
}

class DynamicUserRepository(
    private val dao: DynamicUserDao,
    private val queryBuilder: DynamicQueryBuilder,
    private val auditLogger: AuditLogger,
    private val isProd: Boolean
) {
    fun searchUsers(
        clientIp: String?,
        term: String?,
        includeInactive: Boolean,
        sortField: SortField,
        sortDirection: SortDirection,
        limit: Int,
        offset: Int
    ): List<User> {
        // Environment-specific behavior
        val effectiveLimit = if (isProd) limit.coerceAtMost(100) else limit

        val startTime = System.currentTimeMillis()
        return try {
            val query = queryBuilder.buildUserSearchQuery(
                term = term,
                includeInactive = includeInactive,
                sortField = sortField,
                sortDirection = sortDirection,
                limit = effectiveLimit,
                offset = offset
            )
            val results = dao.searchDynamic(query)
            auditLogger.logSearchAttempt(clientIp, term, success = true)

            val duration = System.currentTimeMillis() - startTime
            if (duration > 500) {
                Log.w("DynamicUserRepository", "Slow search query: ${duration}ms")
            }
            results
        } catch (e: Exception) {
            auditLogger.logSearchAttempt(clientIp, term, success = false)
            Log.e("DynamicUserRepository", "Error during dynamic user search", e)
            emptyList()
        }
    }
}

class RateLimiter(private val maxPerMinute: Int) {
    // Simplified in-memory example; use a robust solution in real apps
    private var count: Int = 0
    private var windowStart: Long = System.currentTimeMillis()

    @Synchronized
    fun allow(): Boolean {
        val now = System.currentTimeMillis()
        if (now - windowStart > 60_000) {
            windowStart = now
            count = 0
        }
        if (count >= maxPerMinute) return false
        count++
        return true
    }
}

class UserSearchController(
    private val repository: DynamicUserRepository,
    private val rateLimiter: RateLimiter
) {
    fun handleRequest(
        clientIp: String?,
        term: String?,
        includeInactive: Boolean,
        sortField: SortField,
        sortDirection: SortDirection,
        limit: Int,
        offset: Int
    ): List<User> {
        if (!rateLimiter.allow()) {
            Log.w("UserSearchController", "Rate limit exceeded for $clientIp")
            return emptyList()
        }
        // This is where you'd also enforce authz and set security headers in a real API
        return repository.searchUsers(
            clientIp,
            term,
            includeInactive,
            sortField,
            sortDirection,
            limit,
            offset
        )
    }
}
```

**Defense in Depth Layers**:
1. **Constrained SQL construction**: Only value placeholders (`?`) receive user-influenced data; dynamic parts like column names and directions are derived from enums (`SortField`, `SortDirection`), preventing arbitrary SQL fragments.
2. **Rate limiting and pagination control**:
   ```kotlin
   if (!rateLimiter.allow()) {
       Log.w("UserSearchController", "Rate limit exceeded for $clientIp")
       return emptyList()
   }
   ```
   This limits abuse (e.g., automated scraping or probing for edge-case payloads) and reduces impact of bugs.
3. **Monitoring, audit logging, and performance alerts**:
   ```kotlin
   auditLogger.logSearchAttempt(clientIp, term, success = true)
   if (duration > 500) {
       Log.w("DynamicUserRepository", "Slow search query: ${duration}ms")
   }
   ```
   This provides visibility into abnormal queries, potential abuse, and performance issues.

**Additional Protections**:
- Enforce strict authentication/authorization in the layer that calls `UserSearchController`, ensuring only authorized users can search and see certain records.
- Apply environment-specific settings: tighter `limit` caps and more aggressive logging/alerting in production, while allowing more flexibility in development.
- Add endpoint-level protections (e.g., TLS, HTTP security headers, and input size limits) in your networking layer or web framework to complement the database-level defenses.

Allowing other apps to control parts of your SQL query inside a `ContentProvider` is dangerous if you build the SQL with string concatenation. Attackers can inject arbitrary conditions, bypass access checks, or even manipulate your database.

**VULNERABLE CODE**:

