For production, you can safely support dynamic WHERE clauses by strictly controlling which fields and operators are allowed and always binding values as parameters. Combine this with WebView hardening, audit logging, and environment-aware configuration.

**PRODUCTION PATTERN**:

```kotlin
import android.annotation.SuppressLint
import android.content.Context
import android.database.Cursor
import android.database.sqlite.SQLiteDatabase
import android.database.sqlite.SQLiteOpenHelper
import android.os.Bundle
import android.util.Log
import android.webkit.JavascriptInterface
import android.webkit.WebChromeClient
import android.webkit.WebResourceRequest
import android.webkit.WebSettings
import android.webkit.WebView
import android.webkit.WebViewClient
import androidx.appcompat.app.AppCompatActivity
import org.json.JSONArray
import org.json.JSONObject

private const val TAG_PROD = "ProdSearch"

class ProdSearchDbHelper(context: Context) : SQLiteOpenHelper(context, "app.db", null, 1) {
    override fun onCreate(db: SQLiteDatabase) {
        db.execSQL("CREATE TABLE users (id INTEGER PRIMARY KEY, username TEXT, email TEXT)")
    }

    override fun onUpgrade(db: SQLiteDatabase, oldVersion: Int, newVersion: Int) {
        db.execSQL("DROP TABLE IF EXISTS users")
        onCreate(db)
    }
}

class DynamicSearchInterface(private val db: SQLiteDatabase, private val isProd: Boolean) {

    // Allowed columns to filter on
    private val allowedFields = setOf("username", "email")

    @JavascriptInterface
    fun searchUsers(jsonFilters: String?): String {
        if (jsonFilters == null) return "[]"

        return try {
            val filtersArray = JSONArray(jsonFilters)
            val whereClauses = mutableListOf<String>()
            val args = mutableListOf<String>()

            // Build dynamic, but controlled, WHERE clause
            for (i in 0 until filtersArray.length()) {
                val filter = filtersArray.getJSONObject(i)
                val field = filter.optString("field")
                val op = filter.optString("op", "contains")
                val value = filter.optString("value", "")

                if (field !in allowedFields) {
                    Log.w(TAG_PROD, "Rejected filter on disallowed field: $field")
                    continue
                }

                if (value.length > 100) {
                    Log.w(TAG_PROD, "Rejected filter with overly long value: len=${value.length}")
                    continue
                }

                when (op) {
                    "eq" -> {
                        whereClauses.add("$field = ?")
                        args.add(value)
                    }
                    "contains" -> {
                        whereClauses.add("$field LIKE ?")
                        args.add("%$value%")
                    }
                    else -> {
                        Log.w(TAG_PROD, "Rejected unsupported operator: $op")
                    }
                }
            }

            val selection = if (whereClauses.isEmpty()) null else whereClauses.joinToString(" AND ")
            val selectionArgs = if (args.isEmpty()) null else args.toTypedArray()

            var cursor: Cursor? = null
            val results = JSONArray()
            try {
                cursor = db.query(
                    "users",
                    arrayOf("id", "username", "email"),
                    selection,
                    selectionArgs,
                    null,
                    null,
                    "username ASC",
                    "100" // limit for rate limiting / DoS protection
                )

                while (cursor.moveToNext()) {
                    val obj = JSONObject()
                    obj.put("id", cursor.getInt(0))
                    obj.put("username", cursor.getString(1))
                    obj.put("email", cursor.getString(2))
                    results.put(obj)
                }
            } finally {
                cursor?.close()
            }

            // AUDIT LOGGING (minimal data, no PII content)
            Log.i(
                TAG_PROD,
                "searchUsers executed with ${whereClauses.size} filters, results=${results.length()}"
            )

            results.toString()
        } catch (e: Exception) {
            // Fail securely: log internally, generic JSON error externally
            Log.e(TAG_PROD, "Error in searchUsers", e)
            "[]"
        }
    }
}

